const e={maxFlow:{intro:{t:0,b:{t:2,i:[{t:3}],s:"Encuentra el mayor flujo volumétrico (mm³/s) que tu hotend puede mantener — aumentando el flujo progresivamente mientras vigilas la carga StallGuard del extrusor hasta el momento en que el engranaje patina. Previsualiza primero el plan; la prueba en vivo calienta y extruye, así que prepara la impresora antes de ejecutarla."}},help:{guide:{t:0,b:{t:2,i:[{t:3}],s:"Ayuda"}},guideTitle:{t:0,b:{t:2,i:[{t:3}],s:"Acerca de Max-Flow"}},close:{t:0,b:{t:2,i:[{t:3}],s:"Cerrar"}},howToRead:{t:0,b:{t:2,i:[{t:3}],s:"Cómo usar"}},steps:[{t:0,b:{t:2,i:[{t:3}],s:"Establece la temperatura de prueba y el diámetro de tu filamento (elige un hotend para precargar valores)."}},{t:0,b:{t:2,i:[{t:3}],s:"Previsualiza el plan — muestra cada paso de flujo y cuánto filamento empuja."}},{t:0,b:{t:2,i:[{t:3}],s:"Marca la lista de seguridad y luego ejecuta la prueba en vivo (calienta + extruye)."}},{t:0,b:{t:2,i:[{t:3}],s:"Lee el flujo máximo sostenido y copia el valor sugerido para el laminador."}}],topics:{howItWorks:{title:{t:0,b:{t:2,i:[{t:3}],s:"Cómo funciona la prueba"}},body:{t:0,b:{t:2,i:[{t:3}],s:"El extrusor empuja filamento a un flujo volumétrico que aumenta de forma constante. Mientras el engranaje dentado agarra limpiamente, la lectura de carga StallGuard se mantiene estable; en cuanto empieza a patinar, las lecturas se disparan de forma errática. El flujo más alto alcanzado antes de ese salto es tu flujo máximo sostenible. La rampa se detiene en cuanto se detecta el patinaje, de modo que no se desgasta filamento más allá del primer patinaje."}}},stallguard:{title:{t:0,b:{t:2,i:[{t:3}],s:"Detección de patinaje con StallGuard"}},body:{t:0,b:{t:2,i:[{t:3}],s:"StallGuard es una función del controlador TMC que informa de la carga del motor. Esta prueba la muestrea muchas veces por paso de flujo y busca un aumento súbito en la dispersión (IQR) o la variación (CV) — la señal de que el engranaje pierde agarre. Los umbrales provienen de un perfil por controlador. Nota: en un extrusor TMC2209 esto usa la ruta experimental SG4, así que trata la primera ejecución como una calibración."}}},safety:{title:{t:0,b:{t:2,i:[{t:3}],s:"Seguridad"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Esta es una prueba caliente y en movimiento que hace patinar el extrusor deliberadamente. Carga filamento, asegúrate de que la boquilla esté despejada (sobre la cama o una zona de desecho) y permanece cerca. La ejecución se rechaza mientras la impresora está imprimiendo, y el calentador siempre se apaga al terminar."}}},slicer:{title:{t:0,b:{t:2,i:[{t:3}],s:"Uso del resultado"}},body:{t:0,b:{t:2,i:[{t:3}],s:'Pon el valor sugerido en el campo "max volumetric speed" de tu laminador (por filamento). La cifra conservadora (80 % del máximo medido) es un límite seguro para el día a día; la cifra equilibrada (90 %) fuerza un poco más. Temperaturas de hotend más altas suelen aumentar el flujo alcanzable.'}}},glossary:{title:{t:0,b:{t:2,i:[{t:3}],s:"Glosario"}},body:{t:0,b:{static:"",t:2,i:[]}}}},glossary:{flow:{term:{t:0,b:{t:2,i:[{t:3}],s:"Flujo volumétrico"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Cuánto plástico funde el hotend por segundo (mm³/s) — el verdadero límite de velocidad para imprimir rápido."}}},stallguard:{term:{t:0,b:{t:2,i:[{t:3}],s:"StallGuard"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Una señal del controlador TMC que informa de la carga mecánica del motor, usada aquí para detectar el patinaje del extrusor."}}},slip:{term:{t:0,b:{t:2,i:[{t:3}],s:"Patinaje"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Cuando el engranaje del extrusor ya no puede agarrar el filamento con suficiente rapidez y patina — el techo del flujo."}}},meltzone:{term:{t:0,b:{t:2,i:[{t:3}],s:"Zona de fusión"}},def:{t:0,b:{t:2,i:[{t:3}],s:"La longitud calentada del hotend; una zona de fusión más larga (p. ej. Volcano) sostiene un flujo mayor."}}}}},params:{title:{t:0,b:{t:2,i:[{t:3}],s:"Parámetros de la prueba"}},temperature:{t:0,b:{t:2,i:[{t:3}],s:"Temperatura (°C)"}},filamentDiameter:{t:0,b:{t:2,i:[{t:3}],s:"Ø de filamento (mm)"}},hotend:{t:0,b:{t:2,i:[{t:3}],s:"Hotend (opcional)"}},hotendNone:{t:0,b:{t:2,i:[{t:3}],s:"— ninguno —"}},hotendHint:{t:0,b:{t:2,i:[{t:3,v:"Esperado ~"},{t:4,k:"flow"},{t:3,v:" mm³/s"}]}},startFlow:{t:0,b:{t:2,i:[{t:3}],s:"Flujo inicial (mm³/s)"}},endFlow:{t:0,b:{t:2,i:[{t:3}],s:"Flujo final (mm³/s)"}},stepFlow:{t:0,b:{t:2,i:[{t:3}],s:"Paso (mm³/s)"}},samples:{t:0,b:{t:2,i:[{t:3}],s:"Muestras / paso"}},extrudePerStep:{t:0,b:{t:2,i:[{t:3}],s:"Extrusión / paso (mm)"}}},plan:{button:{t:0,b:{t:2,i:[{t:3}],s:"Previsualizar plan"}},title:{t:0,b:{t:2,i:[{t:3}],s:"Rampa planificada"}},stepCount:{t:0,b:{t:2,i:[{t:4,k:"count"},{t:3,v:" pasos"}]}},totalExtrude:{t:0,b:{t:2,i:[{t:4,k:"mm"},{t:3,v:" mm de filamento"}]}},sgField:{t:0,b:{t:2,i:[{t:3,v:"Campo StallGuard: "},{t:4,k:"field"}]}},sgFieldUnknown:{t:0,b:{t:2,i:[{t:3}],s:"No se conoce ningún campo StallGuard para este controlador"}},flowHead:{t:0,b:{t:2,i:[{t:3}],s:"Flujo (mm³/s)"}},feedrateHead:{t:0,b:{t:2,i:[{t:3}],s:"Avance (mm/min)"}},warning:{t:0,b:{t:2,i:[{t:3}],s:"La prueba en vivo calienta el hotend y extruye filamento, deliberadamente hasta el punto de patinaje. Solo previsualización — todavía no se ejecuta nada."}}},safety:{title:{t:0,b:{t:2,i:[{t:3}],s:"Antes de ejecutar — lista de comprobación de seguridad"}},items:[{t:0,b:{t:2,i:[{t:3}],s:"El filamento está cargado y avanza libremente."}},{t:0,b:{t:2,i:[{t:3}],s:"La boquilla está despejada — sobre la cama o un recipiente de desecho, no en el aire sobre las piezas."}},{t:0,b:{t:2,i:[{t:3}],s:"Acepto que esto desgastará/hará patinar algo de filamento deliberadamente."}},{t:0,b:{t:2,i:[{t:3}],s:"Permaneceré junto a la impresora durante toda la prueba."}}],ack:{t:0,b:{t:2,i:[{t:3}],s:"He hecho todo lo anterior y la impresora está lista"}},note:{t:0,b:{t:2,i:[{t:3}],s:"La ejecución se rechaza mientras se imprime; el calentador se apaga automáticamente al final."}}},run:{button:{t:0,b:{t:2,i:[{t:3}],s:"Ejecutar prueba en vivo"}},running:{t:0,b:{t:2,i:[{t:3}],s:"Ejecutando… (calentando + extruyendo)"}},confirmTitle:{t:0,b:{t:2,i:[{t:3}],s:"¿Iniciar la prueba de flujo máximo en vivo?"}},confirmBody:{t:0,b:{t:2,i:[{t:3,v:"Esto calienta el hotend a "},{t:4,k:"temp"},{t:3,v:" °C y extruye hasta "},{t:4,k:"mm"},{t:3,v:" mm de filamento, aumentando la rampa hasta que el extrusor patina."}]}},confirm:{t:0,b:{t:2,i:[{t:3}],s:"Ejecutar ahora"}},cancel:{t:0,b:{t:2,i:[{t:3}],s:"Cancelar"}},busy:{t:0,b:{t:2,i:[{t:3}],s:"Rechazado: la impresora está ocupada (imprimiendo o en pausa). Inténtalo de nuevo cuando esté inactiva."}},error:{t:0,b:{t:2,i:[{t:3}],s:"La prueba falló."}},noSg:{t:0,b:{t:2,i:[{t:3}],s:"No se leyeron muestras de StallGuard — el resultado de patinaje puede no ser fiable. Probablemente haya que ajustar el campo SG en vivo del controlador para este modelo."}}},result:{title:{t:0,b:{t:2,i:[{t:3}],s:"Resultado"}},maxFlow:{t:0,b:{t:2,i:[{t:3}],s:"Flujo máximo sostenido"}},slipAt:{t:0,b:{t:2,i:[{t:3,v:"Patinaje detectado a "},{t:4,k:"flow"},{t:3,v:" mm³/s"}]}},noSlip:{t:0,b:{t:2,i:[{t:3}],s:"Sin patinaje hasta el flujo más alto probado"}},reason:{t:0,b:{t:2,i:[{t:3}],s:"Detalle"}},recommendTitle:{t:0,b:{t:2,i:[{t:3}],s:"Valores sugeridos para el laminador (max volumetric speed)"}},conservative:{t:0,b:{t:2,i:[{t:3}],s:"Conservador (80 %)"}},balanced:{t:0,b:{t:2,i:[{t:3}],s:"Equilibrado (90 %)"}},units:{t:0,b:{t:2,i:[{t:3}],s:"mm³/s"}}},states:{loadingHotends:{t:0,b:{t:2,i:[{t:3}],s:"Cargando hotends…"}}}}};export{e as default};
